def main():
    with open(CSV_PATH, encoding="utf-8") as f:
        reader = csv.DictReader(f)
        fieldnames = reader.fieldnames
        existing = list(reader)

    existing_greek = {r["greek"].strip().lower() for r in existing}
    added = 0
    for word in NEW_WORDS:
        if word["greek"].strip().lower() not in existing_greek:
            row = {fn: word.get(fn, "") for fn in fieldnames}
            existing.append(row)
            added += 1
        else:
            print(f"  skip (duplicate): {word['greek']}")

    with open(CSV_PATH, "w", encoding="utf-8", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        writer.writerows(existing)

    print(f"\nAdded {added} new words. Total: {len(existing)}")


if __name__ == "__main__":
    main()
